// Filtrar cancelados elegíveis para D+0
// Regras: não foram contactados ainda, não marcados como nao_retorna, não insatisfação
const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

const elegíveis = $input.all()
  .filter(item => {
    const r = item.json;
    if (!r.whatsapp) return false;
    if (r.nao_retorna === 'TRUE') return false;
    if (r.motivo_cancelamento === 'insatisfacao') return false; // escalar para Rogério
    if (r.D0_enviado) return false; // já recebeu D+0
    if (!r.segmento_reativacao) return false; // Karine não segmentou ainda
    return true;
  })
  .slice(0, 30); // máximo 30 por rodada

console.log(`Elegíveis D+0: ${elegíveis.length}`);
return elegíveis;

// Filtrar cancelados em D+2 ou D+5 para follow-up automático
const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

const diaEmDias = (dataStr) => {
  if (!dataStr) return -1;
  const d = new Date(dataStr);
  d.setHours(0, 0, 0, 0);
  return Math.floor((hoje - d) / (1000 * 60 * 60 * 24));
};

const acoes = [];

for (const item of $input.all()) {
  const r = item.json;
  if (!r.whatsapp) continue;
  if (r.nao_retorna === 'TRUE') continue;
  if (r.reativado === 'TRUE') continue;

  const diasD0 = diaEmDias(r.D0_enviado);

  // D+2: tem D+0 enviado há 2+ dias e D2 ainda não enviado
  if (diasD0 >= 2 && !r.D2_enviado) {
    acoes.push({ ...r, fase: 'D2' });
  }

  // D+5: tem D+2 enviado há 3+ dias (D+5 do D+0) e D5 ainda não enviado
  const diasD2 = diaEmDias(r.D2_enviado);
  if (diasD2 >= 3 && !r.D5_enviado) {
    acoes.push({ ...r, fase: 'D5' });
  }

  // D+7: marcar como frio se D5 foi há 2+ dias e não reativou
  const diasD5 = diaEmDias(r.D5_enviado);
  if (diasD5 >= 2 && !r.data_frio) {
    acoes.push({ ...r, fase: 'MARCAR_FRIO' });
  }
}

console.log(`Ações follow-up: ${acoes.length}`);
return acoes.map(a => ({ json: a }));

// Montar mensagem D+0 por segmento
const r = $input.first().json;
const nome = r.nome_membro || 'Cliente';
const seg = (r.segmento_reativacao || 'C').toUpperCase();

const mensagens = {
  A: `Oi ${nome}! Aqui é a Karine da SST Card 😊\n\nFiquei sabendo que você saiu por conta do valor — entendo, o orçamento aperta mesmo.\n\nQuero te fazer uma proposta: a gente reformulou o SST Card. Agora por *R$39,90/mês* você e mais 3 da sua família têm acesso a consultas, laboratório e telemedicina. Quer que eu te mande os detalhes?`,

  B: `Oi ${nome}! Saudade de você aqui na SST 😊\n\nSei que quando a gente está bem de saúde esquece de usar o cartão — mas é exatamente por isso que ele existe: pra cuidar antes de precisar de emergência.\n\nVocê sabia que consulta de rotina está incluída no seu plano? Posso te ajudar a agendar uma essa semana, sem custo adicional. Quer?`,

  C: `Oi ${nome}! Aqui é a Karine da SST Card.\n\nNotei que você não está mais com a gente e queria saber como você está 😊 Tem alguma coisa que a gente podia ter feito diferente?\n\nEstamos com uma novidade boa: o SST Card agora inclui telemedicina + auxílio funeral + assistência veterinária pelo mesmo valor. Se quiser saber mais, é só me chamar!`
};

const texto = mensagens[seg] || mensagens.C;
return [{ json: { ...r, mensagem: texto, fase: 'D0' } }];

// Montar mensagem de follow-up (D+2 ou D+5) por segmento
const r = $input.first().json;
const nome = r.nome_membro || 'Cliente';
const seg = (r.segmento_reativacao || 'C').toUpperCase();
const fase = r.fase; // 'D2' ou 'D5'

const mensagens = {
  D2: {
    A: `${nome}, você teve chance de pensar na proposta? 😊\n\nSó pra complementar: a taxa de adesão única é R$35 e o plano Individual de R$39,90 já inclui titular + 3 dependentes na saúde. Pix ou débito na clínica.\n\nPositivo, negativo ou qualquer dúvida — só me fala aqui.`,
    B: `${nome}, só passando pra confirmar — você topa que eu reserve um horário de consulta essa semana? Sem compromisso, é parte do seu benefício.\n\nBasta me dizer qual dia fica melhor: manhã ou tarde?`,
    C: `${nome}, ficou alguma dúvida sobre as novidades do SST Card?\n\nSe quiser, posso te mandar um resumo rápido de tudo que você teria acesso por R$39,90/mês. É literalmente R$1,33/dia pra sua família ter saúde de verdade.`
  },
  D5: {
    A: `${nome}, última vez que te contato sobre o SST Card 😊 Só queria deixar claro: se um dia o orçamento melhorar, a porta está aberta. Não precisa pagar taxa de adesão novamente se voltar em até 90 dias.\n\nQualquer coisa, é só me chamar. Cuide-se!`,
    B: `${nome}, vou deixar você em paz depois de hoje — prometo 😄 Mas antes: a gente tem uma consulta de saúde preventiva gratuita disponível para ex-membros esse mês. Posso reservar uma pra você?`,
    C: `${nome}, encerrando por aqui. Se mudar de ideia sobre o SST Card, pode me chamar quando quiser. Valeu pelo tempo que esteve com a gente — foi um prazer te ter como membro!`
  }
};

const texto = (mensagens[fase] || {})[seg] || mensagens.D5.C;
return [{ json: { ...r, mensagem: texto } }];

// Atualizar coluna correta conforme a fase enviada
const r = $input.first().json;
const hoje = new Date().toISOString().split('T')[0];
const fase = r.fase; // 'D2' ou 'D5'

const atualizacao = fase === 'D2'
  ? { D2_enviado: hoje, fase_reativacao: 'D2' }
  : { D5_enviado: hoje, fase_reativacao: 'D5' };

return [{ json: { ...r, atualizacao } }];
